23	const PROCESSING_FEE = 5;
24	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
25	
26	const BASE_PREMIUMS: Record<string, number> = {
27	  sword: 100,
28	  amulet: 60,
29	  staff: 80,
30	};
31	
32	export function processScenario(scenario: Scenario): ScenarioOutput {
33	  const step = scenario.steps[0];
34	  if (step.items.length === 0) {
35	    return { results: [{ premium: PROCESSING_FEE }] };
36	  }
37	  const basePremium = BASE_PREMIUMS[step.items[0].type];
38	  const surcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
39	  const premium = basePremium + surcharge + PROCESSING_FEE;
40	  return { results: [{ premium }] };
41	}
